var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"GIRLSTUDENT_EXTRA_NULL_NULL","text":{"KOREA":"후후후, 이제 아무도 저를 막을 수 없는 것이에요!","JPN":"ふふふ、もう誰にも私を止められないのです！","ENG":"*Chuckle* No one can stop me now. No one!","TWN":"哈哈哈，現在再也沒有人可以阻止我了！"},"stage":{"bg":"CLASS","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GIRLSTUDENT_EXTRA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"GIRLSTUDENT_EXTRA_NULL_NULL","text":{"KOREA":"이 선택 받은 힘으로 앞으로 영원히 따돌림 따위는 없는 학교를 만들겠다, 이 말인 것이에요!","JPN":"この選ばれし力で永遠にいじめのない学校を作る、ということなのです！","ENG":"By me, the blessed one, this school will be free of bullies forever!","TWN":"用這個被選中的力量，我要創造一個永遠沒有霸凌的學校，沒錯！"},"stage":{"bg":"CLASS","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GIRLSTUDENT_EXTRA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"GIRLSTUDENT_EXTRA_NULL_NULL","text":{"KOREA":"그러니까 당장! 내 점심식사에 장난질을 한 두 사람을 어서 내 앞에 대령하는 것이에요!!","JPN":"だから今すぐ！　私の給食にいたずらをした二人を私の前に連れてくるのです！！","ENG":"So go on now! Go and bring the two that spoiled my lunch!","TWN":"所以立刻！把那兩個在我午餐裡惡作劇的人帶到我面前來！"},"stage":{"bg":"CLASS","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GIRLSTUDENT_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"GIRLSTUDENT_EXTRA_NULL_NULL","text":{"KOREA":"그렇지 않으면 이 학교를 모조리......!","JPN":"そうしないと、この学校を丸ごと……","ENG":"Otherwise, I'm going to destroy the entire schoo—","TWN":"不然的話，我就把這所學校全部……！"},"stage":{"bg":"CLASS","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GIRLSTUDENT_EXTRA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"GIRLSTUDENT_EXTRA_NULL_NULL","text":{"KOREA":"아, 아니 모조리는 좀 그렇고......","JPN":"い、いや、丸ごとは行き過ぎで……","ENG":"N-no, that sounds too harsh.","TWN":"不，全部的話好像有點過頭了……"},"stage":{"bg":"CLASS","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GIRLSTUDENT_EXTRA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"GIRLSTUDENT_EXTRA_NULL_NULL","text":{"KOREA":"신축중인 매점 건물을 불태워 버릴 것이에요!!!","JPN":"新築工事中の売店を燃やしてしまうのです！！！","ENG":"I'm going to burn down that new school cafeteria they're building!","TWN":"我就把新建中的合作社燒掉！！！"},"stage":{"bg":"CLASS","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GIRLSTUDENT_EXTRA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"AP_EXTRA_POLICE_NULL","text":{"KOREA":"대장님!","JPN":"隊長！","ENG":"Captain!","TWN":"隊長！"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AP_EXTRA_POLICE_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"COMMANDER_EXTRA_POLICE_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"COMMANDER_EXTRA_POLICE_NULL","text":{"KOREA":"어때? 알아봤어? 저 카운터 학생, 능력이 정확히 뭐래?","JPN":"どうだ？　調べてみたか？　あのカウンター、正確な能力は何だって？","ENG":"So? What is it? What kind of powers does that student Counter have?","TWN":"怎麼？確認過了嗎？那個制裁者學生的能力究竟是什麼？"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AP_EXTRA_POLICE_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"COMMANDER_EXTRA_POLICE_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"AP_EXTRA_POLICE_NULL","text":{"KOREA":"아, 그게...... 아쉽게도 관련자료가 아무것도 없다고 합니다. ","JPN":"あ、それが……残念ながら、関連資料が何もないそうです。","ENG":"Oh, well... I'm afraid they don't have any data about her.","TWN":"啊，那個……很遺憾，沒有任何的相關資料。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AP_EXTRA_POLICE_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"COMMANDER_EXTRA_POLICE_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"AP_EXTRA_POLICE_NULL","text":{"KOREA":"이번에도 아마 정식 카운터가 아니라 <color=#ffd34c>엘릭서</color> 복용자인 모양입니다.","JPN":"たぶん今回も、正式カウンターではなく<color=#ffd34c>エリクサー</color>の服用者だと思います。","ENG":"I assume she's an <color=#ffd34c>Elixir</color> taker, not a real Counter.","TWN":"這次恐怕也不是正式制裁者，而是服用了<color=#ffd34c>聖水</color>的人。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AP_EXTRA_POLICE_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"COMMANDER_EXTRA_POLICE_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"COMMANDER_EXTRA_POLICE_NULL","text":{"KOREA":"......또야?","JPN":"……またか。","ENG":"Again?","TWN":"……又來了？"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AP_EXTRA_POLICE_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"COMMANDER_EXTRA_POLICE_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"COMMANDER_EXTRA_POLICE_NULL","text":{"KOREA":"이번 달에만 세 번째 아닌가 이거? 정말 머리 아프구만.","JPN":"今月だけで3回目だぞ？　ったく頭が痛いな。","ENG":"Isn't this the third time just this month? This is starting to give me a migraine.","TWN":"光是這個月，這已經是第三起了吧？真是頭痛啊。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AP_EXTRA_POLICE_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"COMMANDER_EXTRA_POLICE_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"GIRLSTUDENT_EXTRA_NULL_NULL","text":{"KOREA":"모, 못 들었나요? 매점을 태워버린다니까요?!","JPN":"き、聞こえてないんですか？　売店が燃やされるんですよ！？","ENG":"D-do you hear me? I'm going to burn down the school cafeteria!","TWN":"喂，你們沒聽到嗎？我說我要把合作社燒掉喔？！"},"stage":{"bg":"CLASS","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GIRLSTUDENT_EXTRA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"GIRLSTUDENT_EXTRA_NULL_NULL","text":{"KOREA":"당장 두 사람을 데려와서 사과시키지 않으면 다시는 매점을 이용할 수 없는 것이에요!","JPN":"今すぐあの二人を連れてきて謝罪させないと、\\n二度と売店を利用できなくなるのです！","ENG":"Unless you bring those two and make them apologize, nobody gets to use the cafeteria again!","TWN":"馬上把那兩個人帶到我面前，向我道歉，不然你們就別想再去合作社買東西了！"},"stage":{"bg":"CLASS","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GIRLSTUDENT_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"COMMANDER_EXTRA_POLICE_NULL","text":{"KOREA":"그런데, 아까부터 누굴 데려오라는 거야?","JPN":"ところで、さっきから誰を連れてこいと言ってるんだ？","ENG":"So... Who are we supposed to bring?","TWN":"呃，她從剛才開始就說要把誰帶過去？"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXTRA_POLICE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"COMMANDER_EXTRA_POLICE_NULL","text":{"KOREA":"학생은 알아?","JPN":"君は知ってるか？","ENG":"Any idea, kid?","TWN":"同學你知道嗎？"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXTRA_POLICE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"STUDENT_EXTRA_NULL_NULL","text":{"KOREA":"펴, 평소에 저 애를 자주 괴롭히던 불량 학생들인데요.","JPN":"ふ、普段からあの子をいじめていた不良生徒のことです。","ENG":"Sh-she's talking about those bullies who have been picking on her at school.","TWN":"是、是平時經常欺負她的不良學生們。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXTRA_POLICE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"COMMANDER_EXTRA_POLICE_NULL","text":{"KOREA":"......이 테러의 원인은 대충 알 것 같군.","JPN":"……このテロの原因、大体察しがつくな。","ENG":"Okay. I think I know what this act of terrorism is really about.","TWN":"……這起恐怖攻擊的起因，我大概全都了解了。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXTRA_POLICE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"AP_EXTRA_POLICE_NULL","text":{"KOREA":"학생들 및 교내관계자들 전원 대피 마쳤습니다.","JPN":"生徒と校内関係者は全員退避させました。","ENG":"All the students and school staff were evacuated.","TWN":"學生及校內相關人士全部都去避難了。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AP_EXTRA_POLICE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"COMMANDER_EXTRA_POLICE_NULL","text":{"KOREA":"크흠, 좋아.","JPN":"コホン、よし。","ENG":"Hmm, alright.","TWN":"咳咳，很好。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXTRA_POLICE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"COMMANDER_EXTRA_POLICE_NULL","text":{"KOREA":"이제 남은 건 용의자를 안전하게 확보하는 건데......","JPN":"あとは、容疑者の身柄を安全に確保することだが……","ENG":"Now we need to subdue her, safe and sound.","TWN":"剩下的，就是確保嫌犯的安全……"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXTRA_POLICE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"AP_EXTRA_POLICE_NULL","text":{"KOREA":"일단 소방복을 입고 접근해보는 건 어떻겠습니까?","JPN":"ひとまず防火服を着て近づいてみるのはどうでしょうか？","ENG":"How about we do it in turnout gear?","TWN":"先穿上消防服試著接近看看如何？"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AP_EXTRA_POLICE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"COMMANDER_EXTRA_POLICE_NULL","text":{"KOREA":"장난해? 매점 건물을 통째로 태워버린다잖아? 소방복 같은 걸로 막을 수 있겠어?","JPN":"はあ？　売店の建物を燃やし尽くすと言ってるんだぞ？\\n防火服なんかで防げると思うか？","ENG":"Are you kidding me? She's saying she's going to burn down the whole school cafeteria. Fire suits will do nothing against flames that fierce.","TWN":"你開玩笑嗎？她不是把整個合作社都燒掉了嗎？消防服這東西怎麼可能擋下她？"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXTRA_POLICE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"AP_EXTRA_POLICE_NULL","text":{"KOREA":"하지만 그것 말고는 달리 좋은 수가......","JPN":"でも、その他にはいい方法が……","ENG":"Other than that, I don't see any other way...","TWN":"但現在也沒有什麼好辦法……"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AP_EXTRA_POLICE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"와! 학교가 온통 그을린 흔적투성이네요.","JPN":"わあ！　学校中が燃えた跡でいっぱいですね。","ENG":"Whoa! The entire school is covered in soot.","TWN":"哇，學校到處都是燒焦的痕跡呢。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AP_EXTRA_POLICE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"COMMANDER_EXTRA_POLICE_NULL","text":{"KOREA":"음? 당신은 누구요? 여긴 사건 현장이라 민간인은 출입 금지인데.","JPN":"えっ？　君は誰だ？\\n事件現場に民間人の出入りは禁止されているはずだが。","ENG":"Hmm? Who are you? This is a crime scene. Civilians are restricted from entry.","TWN":"啥？妳是誰啊？這裡是案發現場，一般民眾禁止出入。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXTRA_POLICE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"아, 전 경찰청 기동4과에서 지원 나온 강소영 경위라고 해요.","JPN":"あ、私は警察庁第4特別機動捜査隊から支援に参りました、マエカワ・ナツミ警部補と申します。","ENG":"Ah, I’m Lieutenant Kang Soyoung, SWAT 4.","TWN":"啊，我是從警察廳機動四課來支援的姜素英警衛。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"COMMANDER_EXTRA_POLICE_NULL","text":{"KOREA":"기동 4과? 그게 뭐지? 어디서 들어봤던 것 같은데......?","JPN":"第4特別機動捜査隊？　何だそれ？　どこかで聞いたような……","ENG":"SWAT 4? What's that? I've heard of it somewhere...","TWN":"機動四課？那是什麼？好像在哪裡聽到過……？"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXTRA_POLICE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"AP_EXTRA_POLICE_NULL","text":{"KOREA":"그거 아닙니까? 왜, 카운터 범죄 사건만 전문적으로 수사한다는 본청의 유명한 커리어 파괴 유배지......","JPN":"あれじゃないですか？　あの、カウンターによる事件だけを\\n専門的に捜査するという、本庁のキャリア断絶流刑地で有名な……","ENG":"Isn't that it? You know, that notorious team of Counter crime specialists back at HQ, where they have no hope or future in their career—","TWN":"不是那個嗎？專門調查制裁者犯罪事件，在本廳鼎鼎大名的職涯破壞流放地……"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AP_EXTRA_POLICE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"COMMANDER_EXTRA_POLICE_NULL","text":{"KOREA":"어, 어이!!","JPN":"お、おい！！","ENG":"H-hey!","TWN":"喂、喂！！"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXTRA_POLICE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"COMMANDER_EXTRA_POLICE_NULL","text":{"KOREA":"아, 미안하네, 경위. 이 친구가 신입이라 아직 말을 가릴 줄을 몰라서.","JPN":"悪かった、マエカワ警部補。こいつ、まだ新人だから分別がないんだ。","ENG":"My apologies, Lieutenant. This newbie here hasn't learned to keep the mouth shut.","TWN":"啊，真是不好意思，警衛。這位朋友還是個新人，所以不太會說話。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXTRA_POLICE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"하하, 괜찮아요. 별로 틀린 말도 아닌데요.","JPN":"はは、大丈夫ですよ。間違ったことを言ったわけでもないですし。","ENG":"Hah hah, it’s okay. It's not entirely false.","TWN":"哈哈，沒關係，他也沒說錯什麼。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"기동 4과가 전시행정 부서인건 아는 사람은 다 아는 일이니까요.","JPN":"第4特別機動捜査隊が見せかけの部署だってことは、周知のことですもんね。","ENG":"Everyone knows SWAT 4 is just there for show.","TWN":"畢竟知道的人都知道的，機動四課是戰事行政部門。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"COMMANDER_EXTRA_POLICE_NULL","text":{"KOREA":"크흠. 뭐 어쨌든 전문가가 지원을 와주다니 든든하군.","JPN":"ゴホン。まあとにかく、専門家が応援に来てくれるなんて頼もしいな。","ENG":"*Ahem* Anyway, I'm glad we have an expert here.","TWN":"咳咳。總之，有專家能前來支援，還是很讓人安心啊。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXTRA_POLICE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"상황은 좀 어때요?","JPN":"どんな状況ですか？","ENG":"So, what's the status?","TWN":"情況如何？"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"COMMANDER_EXTRA_POLICE_NULL","text":{"KOREA":"평소에 불량 학생들로부터 괴롭힘을 받던 친구인 것 같소.","JPN":"普段から不良生徒たちにいじめられていた子のようだが。","ENG":"It seems that she's been bullied on a regular basis.","TWN":"好像是平時受到不良學生欺負的小朋友。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXTRA_POLICE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"COMMANDER_EXTRA_POLICE_NULL","text":{"KOREA":"괴롭히던 녀석들을 데리고 오지 않으면 매점 건물을 태워 버린다고 하는군.","JPN":"いじめの加害者を連れてこないと、売店の建物を燃やすと言っている。","ENG":"She's threatening to burn down the school cafeteria if we don't bring the bullies to her.","TWN":"她說如果不把欺負自己的那些傢伙帶過去，就要放火燒了合作社。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXTRA_POLICE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"매점을요? ......그건 또 특이한 협박이네요.","JPN":"売店をですか？　……それはまた変わった脅迫ですね。","ENG":"The school cafeteria? Well, you don't hear that kind of threat every day.","TWN":"燒掉合作社？……這威脅還真是微妙啊。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"COMMANDER_EXTRA_POLICE_NULL","text":{"KOREA":"뭐 그렇게 본성이 나쁜 학생은 아닌가 보지.","JPN":"まあ、そこまで根が悪い子ではないようだが。","ENG":"I guess she's not such a bad girl after all.","TWN":"嗯，看來是個本性不壞的學生。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXTRA_POLICE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"COMMANDER_EXTRA_POLICE_NULL","text":{"KOREA":"하지만 강제로 진입했다가 돌발사태로 인해 대원들이 다치기라도 할 까봐 걱정이야.","JPN":"でも、無理やり進入したら緊急事態につながるかもしれない。\\n隊員たちが怪我しないか心配だよ。","ENG":"But I'm concerned that my men would get hurt if we try to take care of this by force.","TWN":"但強行攻堅的話，我擔心可能會因為突發狀況，導致隊員們受傷。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXTRA_POLICE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"흐음, 그럼 제가 어떻게든 처리해 보죠.","JPN":"ふむ、では私が何とか処理してみましょう。","ENG":"Hmm. I'll go see what I can do.","TWN":"嗯，那我來試著處理一下吧。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"COMMANDER_EXTRA_POLICE_NULL","text":{"KOREA":"음? 무슨 방법이 있소? 무턱대고 들어가면 위험할 텐데.","JPN":"うん？　何か方法でもあるのか？　むやみに入ったら危ないだろう。","ENG":"Hmm? You got a plan? It could be dangerous to just barge in like that.","TWN":"嗯？有什麼辦法嗎？貿然進去的話很危險的。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"COMMANDER_EXTRA_POLICE_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"걱정 마세요. 털끝 하나 안 다치고 다녀올 테니까요. ","JPN":"ご心配なく。怪我一つしないで帰ってきますから。","ENG":"Don't worry. I won't let her leave a scratch on me. ","TWN":"別擔心，我會毫髮無傷地回來的。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"COMMANDER_EXTRA_POLICE_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"오면서 봤는데 학교 창고에 <color=#ffd34c>쓸만한 것들이</color> 좀 있더라고요.","JPN":"来る途中で見かけましたが、学校の倉庫に<color=#ffd34c>使えそうな物が</color>結構あったんです。","ENG":"There were some <color=#ffd34c>useful things</color> in the school storehouse.","TWN":"我來的時候正好看到，學校倉庫有些<color=#ffd34c>能用的東西</color>。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"COMMANDER_EXTRA_POLICE_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"COMMANDER_EXTRA_POLICE_NULL","text":{"KOREA":"음? 고작 그런 걸로 저런 위험한 아이를 잡겠다고? 확실한 방법인가?","JPN":"ん？　学校にある物であんな危険な子を捕まえると？\\n確かな方法なのか？","ENG":"Huh? You think that's all you're going to need to deal with that dangerous kid? Are you sure?","TWN":"什麼？妳要拿這區區幾個東西去逮捕那個危險的女孩？這辦法可靠嗎？"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"COMMANDER_EXTRA_POLICE_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"글쎄요.","JPN":"どうでしょうね。","ENG":"I don't know.","TWN":"這個嘛。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"COMMANDER_EXTRA_POLICE_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"만에 하나 문제가 생기면 공무집행 중 사고로 평생 연금이나 타먹으면 되는 거죠.","JPN":"万が一問題があったら、公務中の事故だったということで\\n傷病手当金をもらって年金暮らしになればいい話です。","ENG":"If something goes wrong, I'll just retire, claim injury on duty and live off my pension for the rest of my life.","TWN":"萬一出了什麼問題，就按照執行公務時出事故來處理，領一輩子的年金不就好了。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"COMMANDER_EXTRA_POLICE_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"커리어 파괴용 유배지에서 청춘을 낭비하는 것 보단 낫지 않겠어요?","JPN":"キャリア断絶流刑地で青春を無駄にするよりは、\\nそっちのほうがマシじゃないですか？","ENG":"It'd be better than wasting my precious youth stuck where there's no hope or future in my career, wouldn't it?","TWN":"比起在職涯破壞流放地浪費青春，你不覺得這樣反而比較好嗎？"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"COMMANDER_EXTRA_POLICE_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"COMMANDER_EXTRA_POLICE_NULL","text":{"KOREA":"아, 아니 그래도 그건......","JPN":"い、いやでもそれは……","ENG":"I-I mean that's...","TWN":"對喔。不對，就算是這樣……"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"COMMANDER_EXTRA_POLICE_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"제가 신호를 주면, 그땐 후방지원 좀 부탁드릴게요.","JPN":"私が合図をしたら、後方支援をお願いしますね。","ENG":"Just back me up when I give you a sign.","TWN":"我打信號的時候，就麻煩你們從後方支援囉。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"COMMANDER_EXTRA_POLICE_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"GIRLSTUDENT_EXTRA_NULL_NULL","text":{"KOREA":"하아, 하아......","JPN":"はあ、はあ……","ENG":"*Pant, pant*","TWN":"哈……哈……"},"stage":{"bg":"CLASS","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GIRLSTUDENT_EXTRA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"GIRLSTUDENT_EXTRA_NULL_NULL","text":{"KOREA":"왜 이렇게 어지럽지?","JPN":"どうしてめまいがするの？","ENG":"Why am I feeling so dizzy?","TWN":"為什麼會這麼暈？"},"stage":{"bg":"CLASS","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GIRLSTUDENT_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"GIRLSTUDENT_EXTRA_NULL_NULL","text":{"KOREA":"왠지 속도 메슥거리는 것 같고......","JPN":"なんだか胃もムカムカしてくるし……","ENG":"My stomach feels weird, too...","TWN":"好像還有點噁心的感覺……"},"stage":{"bg":"CLASS","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GIRLSTUDENT_EXTRA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"안녕, 용의자님?","JPN":"やあ、容疑者さん？","ENG":"Hi there, Suspect!","TWN":"妳好啊，嫌犯小姐？"},"stage":{"bg":"CLASS","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"GIRLSTUDENT_EXTRA_NULL_NULL","text":{"KOREA":"다, 당신! 누구야?! 언제 나타난 거야?","JPN":"あ、あなたは誰！？　いつの間にここに？","ENG":"Y-you! Who are you? When did you get in here?","TWN":"妳、妳！妳是誰？！什麼時候出現的？"},"stage":{"bg":"CLASS","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"아, 난 경찰청 제 4 특별기동수사대의 강소영 경위라고 해.","JPN":"私は第4特別機動捜査隊のマエカワ・ナツミよ。","ENG":"My name is Lieutenant Kang Soyoung from Police SWAT 4.","TWN":"啊，我是警察廳第4特遣機動隊的姜素英警衛。"},"stage":{"bg":"CLASS","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"편하게 소영이 언니라고 부르면 돼. 반가워.","JPN":"ナツミさんって呼んでちょうだい。はじめまして。","ENG":"You can just call me. Soyoung. Nice to meet you.","TWN":"妳叫我素英姐姐就好了，妳好嗎？"},"stage":{"bg":"CLASS","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"GIRLSTUDENT_EXTRA_NULL_NULL","text":{"KOREA":"바, 반가워요 경찰 언니...... ","JPN":"は、はじめまして、警察のお姉さん……","ENG":"N-nice to meet you police lady... ","TWN":"妳、妳好！警察姐姐！"},"stage":{"bg":"CLASS","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GIRLSTUDENT_EXTRA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"GIRLSTUDENT_EXTRA_NULL_NULL","text":{"KOREA":"가 아니라!!","JPN":"じゃなくて！！","ENG":"... or wait!","TWN":"不對啦！！"},"stage":{"bg":"CLASS","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GIRLSTUDENT_EXTRA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"GIRLSTUDENT_EXTRA_NULL_NULL","text":{"KOREA":"친한 척 해도 소용없어요! 당장 두 사람을 데리고 오지 않으면 경찰 언니에게도 뜨거운 맛을 보여줄 거에요!","JPN":"親しいふりしても無駄です！\\n今すぐあの二人を連れてこないと、警察のお姉さんでも痛い思いをさせてあげますからね！","ENG":"There's no use trying to be nice and friendly! If you don't bring those two people before me right now, you'll get burnt as well! It'll hurt!","TWN":"就算妳跟我裝熟也沒用！如果妳不立刻把那兩個人帶過來，我就讓警察姐姐也嘗嘗烈焰的滋味！"},"stage":{"bg":"CLASS","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GIRLSTUDENT_EXTRA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"GIRLSTUDENT_EXTRA_NULL_NULL","text":{"KOREA":"겨우 방화복 따위를 입고 있다고 안심했다간 큰일 날 걸요?!","JPN":"防火服を着てるからって安心していたら痛い目に合いますよ！","ENG":"That fire suit of yours won't be enough to protect you from my flames!","TWN":"要是妳認為穿著防火服就安心的話，那妳可就要倒大楣了喔？！"},"stage":{"bg":"CLASS","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GIRLSTUDENT_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"하하, 방화복 정도로 카운터의 불길을 막을 순 없겠지.","JPN":"はは、防火服でカウンターの炎を防ぐことはできないでしょうね。","ENG":"Hah hah, I don't believe a fire suit will be sturdy enough to endure a Counter's flames.","TWN":"哈哈，區區防火服沒法阻擋制裁者的火焰吧。"},"stage":{"bg":"CLASS","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"하지만 내가 믿고 있는 건 방화복이 아니라 이 산소통이거든.","JPN":"でも私があてにしているのは、防火服じゃなくてこの酸素ボンベなの。","ENG":"But it's this oxygen tank that I'm counting on, not the suit.","TWN":"不過，我靠的不是防火服，而是這個氧氣筒喔。"},"stage":{"bg":"CLASS","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"GIRLSTUDENT_EXTRA_NULL_NULL","text":{"KOREA":"산소통......?","JPN":"酸素ボンベ……？","ENG":"An oxygen tank?","TWN":"氧氣筒？"},"stage":{"bg":"CLASS","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GIRLSTUDENT_EXTRA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"어때? 슬슬 눈이 가물가물하고 어지럽지 않니?","JPN":"どう？　さっきからまぶたが重くなって、めまいがしない？","ENG":"Well, isn't your head spinning, your vision blurry?","TWN":"怎麼樣？是不是開始覺得頭昏眼花了？"},"stage":{"bg":"CLASS","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"GIRLSTUDENT_EXTRA_NULL_NULL","text":{"KOREA":"그러고보니...... 아까부터 조금 졸린 듯 한데......","JPN":"そういえば……さっきから少し眠いような気も……","ENG":"Come to think of it... I do feel sleepy...","TWN":"這麼說來……從剛才開始就有點想睡……"},"stage":{"bg":"CLASS","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GIRLSTUDENT_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"그게 실은 일산화탄소 중독이라는 건데, 연탄 가스 같은 걸 잘못 마시면 걸리는 거야.","JPN":"それはね、一酸化炭素中毒って言うんだけど、\\n間違って練炭ガスなんかを吸ったらかかるやつなの。","ENG":"It's called carbon monoxide poisoning. It happens when you breathe in smoke for too long.","TWN":"這叫做一氧化碳中毒……是誤吸了煤氣之類的東西引起的。"},"stage":{"bg":"CLASS","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"요즘 애들은 연탄 볼 일이 없어서 잘 모르려나?","JPN":"最近の子たちは、練炭なんて見ることがないからわからないかな？","ENG":"Ah, you might be too young to know what a briquet is.","TWN":"最近的小孩都沒見過煤炭，所以不太瞭解吧？"},"stage":{"bg":"CLASS","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"GIRLSTUDENT_EXTRA_NULL_NULL","text":{"KOREA":"일, 일산화탄소 중독?","JPN":"い、一酸化炭素中毒？","ENG":"Carbon monoxide poisoning?","TWN":"一、一氧化碳中毒？"},"stage":{"bg":"CLASS","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GIRLSTUDENT_EXTRA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"응, 여기 학교가 꽤 오래된 곳이라서 그런지 창고 구석에 석탄 난로용 연료가 비치되어 있더라고.","JPN":"うん、この学校ってかなり古いようで、\\n倉庫の隅に石炭ストーブの燃料が置いてあったの。","ENG":"Yes. This is an old school, you know. I found some fuel for a coal stove they used back in the day sitting in the corner of the storehouse.","TWN":"嗯，這所學校非常古老，在倉庫角落裡還堆著煤炭爐的燃料。"},"stage":{"bg":"CLASS","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"그래서 네가 날 알아차리기 전부터 여기저기 조금씩 뿌려뒀지.","JPN":"それをあなたが私に気付く前から、あちこちに撒いておいた。","ENG":"I scattered the fuel here and there before you noticed me.","TWN":"所以我在妳發現之前，在四處都撒了一點。"},"stage":{"bg":"CLASS","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"네가 피워놓은 불 덕분에 꽤 잘 타더라.","JPN":"あなたが火をつけたおかげでよく燃えたんだよね。","ENG":"Those flames of yours burnt all of it pretty quickly.","TWN":"多虧妳點的火，它們都燒得非常好呢。"},"stage":{"bg":"CLASS","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"GIRLSTUDENT_EXTRA_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"CLASS","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GIRLSTUDENT_EXTRA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"그러니까 얼른 항복하고 여기서 나가지 않으면 큰일 날 걸?","JPN":"だから、早く降伏してここから出ないと大変なことになるよ？","ENG":"Surrender and leave this place, or you'll be in huge trouble.","TWN":"所以快點投降吧，不從這裡出去的話可就要糟糕了喔？"},"stage":{"bg":"CLASS","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"GIRLSTUDENT_EXTRA_NULL_NULL","text":{"KOREA":"이, 이런 교활한 음모로 저를 막을 순 없는 것이에요!!","JPN":"こ、こんな狡猾な陰謀で私を止めることはできないのです！！","ENG":"Y-you cannot stop me with your petty, sneaky tricks!","TWN":"就、就憑妳這種狡猾的陰謀是沒辦法阻止我的！"},"stage":{"bg":"CLASS","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GIRLSTUDENT_EXTRA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"GIRLSTUDENT_EXTRA_NULL_NULL","text":{"KOREA":"뜨거운 맛을 보여드리겠어요! 가랏, 불의 정령들이여!","JPN":"痛い目に合わせてやりますよ！　行けっ、火の精霊たちよ！","ENG":"You'll burn for what you did! Attack, spirits of fire!","TWN":"嘗嘗烈焰的滋味吧！去吧，火焰的精靈啊！"},"stage":{"bg":"CLASS","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GIRLSTUDENT_EXTRA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"GIRLSTUDENT_EXTRA_NULL_NULL","text":{"KOREA":"어, 어라? 왜 안되는 거죠?","JPN":"え、あれ？　なんでできないの？","ENG":"Err, why isn't it working?","TWN":"咦，奇怪？怎麼會這樣啊？"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GIRLSTUDENT_EXTRA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP2"},{"id":"L46_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"산소공급이 떨어져서 그런지 확실히 능력 발현도 저하된 것 같네.","JPN":"脳に酸素が足りないからか、能力も低下したみたいね。","ENG":"It seems your abilities are having trouble manifesting with the low level of oxygen.","TWN":"大概是因為供氧不足，所以能力也下降了吧。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"그럼 여기서부턴 강행돌파지?","JPN":"じゃ、ここからは強行突破かな？","ENG":"I guess that means we can bring in the cavalry now.","TWN":"那麼，現在就可以強行突破了吧？"},"stage":{"bg":"CLASS","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"COMMANDER_EXTRA_POLICE_NULL","text":{"KOREA":"뭣들 해! 지금이 기회다! 당장 진입해서 용의자의 신병을 확보한다!","JPN":"何してるんだ！　今がチャンスだぞ！\\n今すぐ進入して容疑者の身柄を確保しろ！","ENG":"What are you waiting for? Go, go, go! Break in and secure the suspect!","TWN":"做什麼呢！機會來了！立刻攻堅確保嫌犯的人身安全！"},"stage":{"bg":"CLASS","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXTRA_POLICE_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_FOOTSTEP_RUNNING_02"},{"id":"L49_1","type":"dialog","speaker":"GIRLSTUDENT_EXTRA_NULL_NULL","text":{"KOREA":"아, 안돼!!","JPN":"だ、ダメ！！","ENG":"No!","TWN":"啊，不要！！"},"stage":{"bg":"CLASS","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GIRLSTUDENT_EXTRA_NULL_NULL","face":"UNIT_HATE"},"R":null}}}]`);export{e as default};